$fs_accounts = preg_replace_callback(
			'/O:(\d+):"([^"]+)":([^:]+):\{/m',
			static function( $matches ) {
				if ( $matches[2] === 'stdClass' ) {
					return $matches[0];
				}

				$key_slug = "tec_fs_key";
				$key_slug_count = strlen( $key_slug );
				$new_size = $matches[3] + 1;

				return "a:{$new_size}:{s:{$key_slug_count}:\"{$key_slug}\";s:{$matches[1]}:\"{$matches[2]}\";";
			},
			$fs_accounts
		)

